import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Button, Input, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { sxService } from '../../../services/sx/sxService';
import type { BomDto } from '../../../services/sx/models';
import { formatDateLocal } from '../../../utils/format';
import styles from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';

const BomListPage: React.FC = () => {
  const [reloadKey, setReloadKey] = useState(0);
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<BomDto[]>([]);
  const [loading, setLoading] = useState(false);
  const handleSearch = () => setSearch(searchDraft.trim());
  const refresh = () => setReloadKey(k => k + 1);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      sxService
        .getBoms()
        .then(data => { if (!cancelled) setItems(data); })
        .catch(err => {
          if (!cancelled)
            dispatch(addToast({ message: err?.message ?? 'Lỗi tải BOM', type: 'error' }));
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [dispatch, reloadKey]);

  const filtered = items.filter(
    b =>
      !search ||
      b.productCode.toLowerCase().includes(search.toLowerCase()) ||
      (b.productName ?? '').toLowerCase().includes(search.toLowerCase()) ||
      b.code.toLowerCase().includes(search.toLowerCase()),
  );

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-list-alt" /> Danh mục BOM</h1>
        </div>
        <div className={styles.headerActions}>
          <Button variant="primary" onClick={() => navigate('/sx/bom/them')}>
            <i className="fas fa-plus" /> Tạo BOM
          </Button>
        </div>
      </div>

      <div className={styles.filtersBar} data-testid={`erp-bom-filters`}>
        <Input
          placeholder="Tìm mã SP, tên..."
          value={searchDraft}
          onChange={e => setSearchDraft(e.target.value)}
          size="small"
        />
        <ListSearchRefreshButtons testIdPrefix="erp-bom" onSearch={handleSearch} onRefresh={refresh} showSearch={true} />
      </div>

      <div className={styles.tableCard}>
        {loading ? (
          <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
        ) : filtered.length === 0 ? (
          <div className={styles.empty}><i className="fas fa-inbox" /><p>Không có BOM</p></div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Mã BOM</th>
                  <th>Sản phẩm</th>
                  <th>ĐVT</th>
                  <th className={styles.colRight}>SL chuẩn</th>
                  <th>Hiệu lực từ</th>
                  <th className={styles.colRight}>Số NVL</th>
                  <th>Trạng thái</th>
                  <th className={styles.colActions}></th>
                </tr>
              </thead>
              <tbody>
                {filtered.map(b => (
                  <tr key={b.id}>
                    <td>
                      <button type="button" className={styles.codeLink} onClick={() => navigate(`/sx/bom/${b.id}`)}>
                        <code>{b.code}</code>
                      </button>
                    </td>
                    <td>{b.productName ?? b.productCode}</td>
                    <td>{b.unitCode}</td>
                    <td className={styles.colRight}>{b.quantity}</td>
                    <td>{formatDateLocal(b.effectiveFrom)}</td>
                    <td className={styles.colRight}>{b.lines?.length ?? 0}</td>
                    <td>
                      <span className={b.isActive ? styles.tagSuccess : styles.tagDefault}>
                        {b.isActive ? 'Khả dụng' : 'Ngưng'}
                      </span>
                    </td>
                    <td className={styles.colActions}>
                      <button type="button" className={styles.actionBtn} onClick={() => navigate(`/sx/bom/${b.id}`)} title="Sửa">
                        <i className="fas fa-edit" />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
        {filtered.length > 0 && (
          <div className={styles.paginationRow}>
            <span className={styles.totalCount}>Tổng: {filtered.length} BOM</span>
          </div>
        )}
      </div>
    </div>
  );
};

export default BomListPage;
